/* ----------------------------- hooks ------------------------------ */

const useReducedMotion = () => {
  const [reduced, setReduced] = useState(false);
  useEffect(() => {
    const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
    setReduced(mq.matches);
    const fn = (e) => setReduced(e.matches);
    mq.addEventListener("change", fn);
    return () => mq.removeEventListener("change", fn);
  }, []);
  return reduced;
};

const useReveal = () => {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const io = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setInView(true); io.disconnect(); } },
      { threshold: 0.12 }
    );
    io.observe(el);
    return () => io.disconnect();
  }, []);
  return [ref, inView];
};

const Reveal = ({ children, delay = 0, as: Tag = "div", className = "", style = {} }) => {
  const [ref, inView] = useReveal();
  return (
    <Tag ref={ref} className={`reveal ${inView ? "in" : ""} ${className}`} style={{ transitionDelay: `${delay}s`, ...style }}>
      {children}
    </Tag>
  );
};

/* --------------------------- components --------------------------- */

const Cursor = ({ active }) => {
  const dot = useRef(null);
  const ring = useRef(null);
  useEffect(() => {
    if (!active) return;
    let mx = innerWidth / 2, my = innerHeight / 2, rx = mx, ry = my, raf;
    const move = (e) => {
      mx = e.clientX; my = e.clientY;
      if (dot.current) dot.current.style.transform = `translate3d(${mx}px,${my}px,0) translate(-50%,-50%)`;
    };
    const loop = () => {
      rx += (mx - rx) * 0.55; ry += (my - ry) * 0.55;
      if (ring.current) ring.current.style.transform = `translate3d(${rx}px,${ry}px,0) translate(-50%,-50%)`;
      raf = requestAnimationFrame(loop);
    };
    const over = (e) => { if (e.target.closest("a,button,.chip,.xp-head,.spot li")) document.body.classList.add("cursor-hover"); };
    const out = (e) => { if (e.target.closest("a,button,.chip,.xp-head,.spot li")) document.body.classList.remove("cursor-hover"); };
    addEventListener("mousemove", move);
    document.addEventListener("mouseover", over);
    document.addEventListener("mouseout", out);
    raf = requestAnimationFrame(loop);
    return () => { removeEventListener("mousemove", move); document.removeEventListener("mouseover", over); document.removeEventListener("mouseout", out); cancelAnimationFrame(raf); };
  }, [active]);
  if (!active) return null;
  return (<><div ref={dot} className="cursor" /><div ref={ring} className="cursor-ring" /></>);
};

