const ProjectCard = ({ p, reduced, index }) => {
  const ref = useRef(null);
  const onMove = useCallback((e) => {
    if (reduced || !ref.current) return;
    const r = ref.current.getBoundingClientRect();
    const x = (e.clientX - r.left) / r.width - 0.5;
    const y = (e.clientY - r.top) / r.height - 0.5;
    ref.current.style.transform = `perspective(1100px) rotateY(${x * 5}deg) rotateX(${-y * 5}deg)`;
  }, [reduced]);
  const onLeave = () => { if (ref.current) ref.current.style.transform = ""; };
  return (
    <Reveal delay={index * 0.06}>
      <div className={`spot ${p.flip ? "flip" : ""}`} ref={ref} onMouseMove={onMove} onMouseLeave={onLeave}>
        <div>
          <h3>{p.title}</h3>
          <p className="spot-tag">{p.tag}</p>
          <p>{p.desc}</p>
          <ul className="spot-points">{p.points.map((pt) => <li key={pt}>{pt}</li>)}</ul>
          <div className="spot-stack">{p.stack.map((s) => <span key={s}>{s}</span>)}</div>
          <a className="spot-link" href={p.link} target="_blank" rel="noopener noreferrer">{p.linkLabel} <ArrowIcon /></a>
        </div>
        <a className="spot-shot" href={p.link} target="_blank" rel="noopener noreferrer" aria-label={`Open ${p.title}`}>
          <img src={p.shot} alt={p.shotAlt} loading="lazy" />
        </a>
      </div>
    </Reveal>
  );
};

const Magnet = ({ reduced, children, href, onClick, className = "" }) => {
  const ref = useRef(null);
  const onMove = (e) => {
    if (reduced || !ref.current) return;
    const r = ref.current.getBoundingClientRect();
    ref.current.style.transform = `translate(${(e.clientX - r.left - r.width / 2) * 0.25}px, ${(e.clientY - r.top - r.height / 2) * 0.35}px)`;
  };
  const onLeave = () => { if (ref.current) ref.current.style.transform = ""; };
  const Tag = href ? "a" : "button";
  return (
    <Tag ref={ref} className={className} href={href} onClick={onClick} onMouseMove={onMove} onMouseLeave={onLeave}>
      {children}
    </Tag>
  );
};

