const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,600;9..144,800;9..144,900&family=Manrope:wght@300;400;500;600;800&family=Space+Mono:wght@400;700&display=swap');

:root{
  --ink:#0E0E12; --ink-soft:#16161D; --paper:#F5F2EA;
  --danfo:#FFC51F; --danfo-deep:#E8A800; --violet:#8B7BFF;
  --smoke:#9B9BA8; --line:rgba(245,242,234,.12);
  --display:'Fraunces',Georgia,serif;
  --body:'Manrope',system-ui,sans-serif;
  --mono:'Space Mono',ui-monospace,monospace;
}
*{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth}
body{background:#0E0E12}
.site{background:var(--ink);color:var(--paper);font-family:var(--body);font-weight:300;overflow-x:hidden;cursor:none;min-height:100vh}
::selection{background:var(--danfo);color:var(--ink)}
.site a{color:inherit;text-decoration:none}
.site button{font-family:inherit;border:none;background:none;color:inherit;cursor:none}
@media (hover:none),(pointer:coarse){.site,.site button{cursor:auto}.cursor,.cursor-ring{display:none!important}}

.cursor{position:fixed;top:0;left:0;width:8px;height:8px;background:var(--danfo);border-radius:50%;pointer-events:none;z-index:9999;transform:translate3d(-100px,-100px,0) translate(-50%,-50%);will-change:transform;transition:width .2s,height .2s,background .2s}
.cursor-ring{position:fixed;top:0;left:0;width:34px;height:34px;border:1px solid rgba(255,197,31,.55);border-radius:50%;pointer-events:none;z-index:9998;transform:translate3d(-100px,-100px,0) translate(-50%,-50%);will-change:transform;transition:width .25s,height .25s,border-color .25s}
body.cursor-hover .cursor{width:14px;height:14px;background:var(--paper)}
body.cursor-hover .cursor-ring{width:56px;height:56px;border-color:var(--paper)}

.loader{position:fixed;inset:0;background:var(--ink);z-index:10000;display:flex;align-items:center;justify-content:center;flex-direction:column;gap:1.4rem;transition:transform .8s cubic-bezier(.76,0,.24,1)}
.loader.done{transform:translateY(-101%)}
.loader-name{font-family:var(--display);font-weight:900;font-size:clamp(2rem,6vw,4rem);letter-spacing:.02em;display:flex;overflow:hidden;color:var(--paper)}
.loader-name span{display:inline-block;transform:translateY(110%);animation:rise .7s cubic-bezier(.22,1,.36,1) forwards}
.loader-name span:nth-child(odd){color:var(--danfo)}
.loader-bar{width:min(280px,60vw);height:2px;background:var(--line);overflow:hidden}
.loader-bar i{display:block;height:100%;width:0;background:var(--danfo);animation:load 1.4s cubic-bezier(.65,0,.35,1) forwards}
@keyframes rise{to{transform:translateY(0)}}
@keyframes load{to{width:100%}}

nav{position:fixed;top:0;left:0;right:0;z-index:900;display:flex;justify-content:space-between;align-items:center;padding:1.1rem clamp(1.2rem,4vw,3rem);background:linear-gradient(rgba(14,14,18,.85),rgba(14,14,18,0));backdrop-filter:blur(2px)}
.nav-logo{font-family:var(--display);font-weight:900;font-size:1.2rem;letter-spacing:.04em}
.nav-logo b{color:var(--danfo)}
.nav-links{display:flex;align-items:center;gap:clamp(.9rem,2.6vw,2rem);font-family:var(--mono);font-size:.72rem;letter-spacing:.12em;text-transform:uppercase}
.nav-links a{position:relative;padding:.3rem 0}
.nav-links a::after{content:"";position:absolute;left:0;bottom:0;width:100%;height:1px;background:var(--danfo);transform:scaleX(0);transform-origin:right;transition:transform .35s cubic-bezier(.65,0,.35,1)}
.nav-links a:hover::after{transform:scaleX(1);transform-origin:left}
.nav-cv{font-family:var(--mono);font-size:.7rem;letter-spacing:.12em;text-transform:uppercase;border:1px solid var(--danfo);color:var(--danfo);border-radius:100px;padding:.45rem 1rem;transition:.3s}
.nav-cv:hover{background:var(--danfo);color:var(--ink)}
@media(max-width:680px){.nav-links a:not(:last-of-type){display:none}}

.hero{min-height:100svh;display:flex;flex-direction:column;justify-content:center;padding:clamp(5rem,12vh,8rem) clamp(1.2rem,4vw,3rem) 0;position:relative;overflow:hidden}
.hero-grid{position:absolute;inset:0;background-image:linear-gradient(var(--line) 1px,transparent 1px),linear-gradient(90deg,var(--line) 1px,transparent 1px);background-size:72px 72px;-webkit-mask-image:radial-gradient(ellipse 90% 70% at 50% 40%,black 30%,transparent 75%);mask-image:radial-gradient(ellipse 90% 70% at 50% 40%,black 30%,transparent 75%);opacity:.5;animation:gridDrift 22s linear infinite}
@keyframes gridDrift{to{background-position:72px 72px}}
.hero-eyebrow{font-family:var(--mono);font-size:.72rem;letter-spacing:.22em;text-transform:uppercase;color:var(--smoke);display:flex;align-items:center;gap:.7rem;margin-bottom:clamp(1rem,3vh,2rem);position:relative;z-index:2}
.hero-eyebrow::before{content:"";width:34px;height:1px;background:var(--danfo)}
.blink{width:8px;height:8px;border-radius:50%;background:#4ade80;display:inline-block;animation:blink 1.6s infinite}
@keyframes blink{50%{opacity:.25}}
.hero h1{font-family:var(--display);font-weight:900;font-size:clamp(3rem,12vw,10.5rem);line-height:.95;letter-spacing:-.01em;position:relative;z-index:2}
.hero h1 .row{display:block;overflow:hidden}
.hero h1 .row>span{display:inline-block;transform:translateY(112%);transition:transform .9s cubic-bezier(.22,1,.36,1)}
.hero h1 .row>span.up{transform:translateY(0)}
.hero h1 .outline{color:transparent;-webkit-text-stroke:1.5px var(--paper)}
.hero h1 .accent{font-style:italic;color:var(--danfo)}
.hero-sub{display:flex;flex-wrap:wrap;justify-content:space-between;align-items:flex-end;gap:1.5rem;margin-top:clamp(1.5rem,4vh,2.6rem);position:relative;z-index:2}
.hero-role{font-size:clamp(1rem,2vw,1.3rem);font-weight:400;max-width:34ch;color:#D9D6CC}
.hero-role em{font-style:normal;color:var(--danfo);font-weight:600}
.hero-meta{font-family:var(--mono);font-size:.72rem;color:var(--smoke);letter-spacing:.12em;text-align:right;line-height:2}
.scroll-hint{position:absolute;bottom:1.6rem;left:50%;transform:translateX(-50%);font-family:var(--mono);font-size:.62rem;letter-spacing:.3em;color:var(--smoke);text-transform:uppercase;animation:bob 2.4s ease-in-out infinite}
@keyframes bob{50%{transform:translate(-50%,8px)}}

.marquee{background:var(--danfo);color:var(--ink);overflow:hidden;padding:.85rem 0;border-top:3px solid var(--ink);border-bottom:3px solid var(--ink);transform:rotate(-1.2deg) scale(1.02);position:relative;z-index:5}
.marquee-track{display:flex;width:max-content;animation:scrollX 24s linear infinite}
.marquee span{font-family:var(--display);font-weight:800;font-size:clamp(.95rem,1.8vw,1.25rem);letter-spacing:.04em;text-transform:uppercase;padding:0 1.6rem;white-space:nowrap;display:flex;align-items:center;gap:1.6rem}
.marquee span::after{content:"✦"}
@keyframes scrollX{to{transform:translateX(-50%)}}
.marquee:hover .marquee-track{animation-play-state:paused}

section{padding:clamp(4.5rem,12vh,9rem) clamp(1.2rem,4vw,3rem);position:relative}
.sec-label{font-family:var(--mono);font-size:.7rem;letter-spacing:.26em;text-transform:uppercase;color:var(--danfo);display:flex;align-items:center;gap:.8rem;margin-bottom:clamp(2rem,5vh,3.5rem)}
.sec-label::after{content:"";flex:1;height:1px;background:var(--line)}
.reveal{opacity:0;transform:translateY(42px);transition:opacity .8s cubic-bezier(.22,1,.36,1),transform .8s cubic-bezier(.22,1,.36,1)}
.reveal.in{opacity:1;transform:none}

.about-grid{display:grid;grid-template-columns:1.3fr 1fr;gap:clamp(2rem,6vw,5rem);align-items:start}
.about-grid h2{font-family:var(--display);font-weight:600;font-size:clamp(1.8rem,3.8vw,3.1rem);line-height:1.16;letter-spacing:-.01em}
.about-grid h2 em{color:var(--danfo)}
.about-grid p{margin-top:1.4rem;color:#C9C6BD;line-height:1.85;font-size:.98rem;max-width:56ch;font-weight:400}
.skill-cloud{display:flex;flex-wrap:wrap;gap:.6rem}
.chip{font-family:var(--mono);font-size:.72rem;letter-spacing:.05em;padding:.55rem .95rem;border:1px solid var(--line);border-radius:100px;color:#D9D6CC;transition:.3s;display:inline-block}
.chip:hover{background:var(--danfo);color:var(--ink);border-color:var(--danfo);transform:translateY(-4px) rotate(-1.5deg)}
.skill-head{font-family:var(--mono);font-size:.66rem;letter-spacing:.2em;text-transform:uppercase;color:var(--smoke);margin:1.6rem 0 .8rem}
.about-grid>div>div:first-child .skill-head{margin-top:0}
@media(max-width:820px){.about-grid{grid-template-columns:1fr}}

.xp-list{border-top:1px solid var(--line)}
.xp{border-bottom:1px solid var(--line);overflow:hidden;transition:background .4s}
.xp-head{display:grid;grid-template-columns:88px 1.4fr 1fr auto;gap:1.2rem;align-items:center;padding:1.7rem .6rem;transition:padding .35s}
.xp:hover{background:var(--ink-soft)}
.xp:hover .xp-head{padding-left:1.4rem}
.xp-year{font-family:var(--mono);font-size:.72rem;color:var(--smoke);letter-spacing:.06em}
.xp-co{font-family:var(--display);font-weight:800;font-size:clamp(1.2rem,2.5vw,1.8rem);letter-spacing:.005em;transition:color .3s}
.xp:hover .xp-co{color:var(--danfo)}
.xp-role{font-size:.85rem;color:var(--smoke);font-weight:400}
.xp-toggle{width:34px;height:34px;border:1px solid var(--line);border-radius:50%;display:grid;place-items:center;font-size:1rem;color:var(--smoke);transition:.35s;flex-shrink:0}
.xp.open .xp-toggle{transform:rotate(45deg);background:var(--danfo);color:var(--ink);border-color:var(--danfo)}
.xp-body{max-height:0;overflow:hidden;transition:max-height .55s cubic-bezier(.65,0,.35,1)}
.xp-body-inner{padding:0 .6rem 1.9rem;display:grid;grid-template-columns:88px 1fr;gap:1.2rem}
.xp-body-inner.has-img{grid-template-columns:88px 1fr minmax(150px,auto)}
.xp-shot{align-self:start;justify-self:end}
.xp-shot img{display:block;width:150px;height:auto;border-radius:14px;border:1px solid var(--line);box-shadow:0 14px 36px rgba(0,0,0,.45);transform:rotate(1.5deg);transition:transform .35s cubic-bezier(.22,1,.36,1)}
.xp-shot.wide img{width:240px}
.xp-shot img:hover{transform:rotate(0) scale(1.04)}
.xp-body ul{list-style:none;max-width:68ch}
.xp-body li{position:relative;padding-left:1.4rem;margin-bottom:.7rem;color:#C9C6BD;line-height:1.7;font-size:.9rem;font-weight:400}
.xp-body li::before{content:"→";position:absolute;left:0;color:var(--danfo);font-family:var(--mono)}
@media(max-width:720px){
  .xp-head{grid-template-columns:1fr auto;row-gap:.3rem}
  .xp-year{grid-column:1/-1}
  .xp-role{grid-column:1/-1}
  .xp-body-inner,.xp-body-inner.has-img{grid-template-columns:1fr}
  .xp-body-inner .xp-year{display:none}
  .xp-shot img{width:180px;margin:0 auto}
  .xp-shot.wide img{width:min(300px,100%)}
}

.spot-list{display:grid;gap:clamp(2rem,5vh,3.5rem)}
.spot{background:var(--paper);color:var(--ink);border-radius:28px;padding:clamp(2rem,5vw,4rem);display:grid;grid-template-columns:1fr 1.1fr;gap:clamp(2rem,5vw,4rem);align-items:center;transition:transform .25s ease-out;position:relative;overflow:hidden}
.spot.flip>div:first-child{order:2}
.spot.flip .spot-shot{order:1;transform:rotate(-1.2deg)}
.spot.flip .spot-shot:hover{transform:rotate(0) scale(1.02)}
.spot::before{content:"FEATURED";position:absolute;top:1.4rem;right:-2.4rem;background:var(--ink);color:var(--danfo);font-family:var(--mono);font-size:.62rem;letter-spacing:.3em;padding:.45rem 3rem;transform:rotate(35deg);z-index:2}
.spot h3{font-family:var(--display);font-weight:900;font-size:clamp(1.7rem,3.6vw,2.8rem);line-height:1.08;letter-spacing:-.01em}
.spot-tag{font-family:var(--mono);font-size:.7rem;letter-spacing:.14em;text-transform:uppercase;color:var(--danfo-deep);margin-top:.6rem}
.spot p{margin-top:1rem;line-height:1.8;color:#3c3c44;font-size:.95rem;font-weight:400}
.spot-points{list-style:none;margin-top:1.2rem;display:grid;gap:.55rem}
.spot-points li{position:relative;padding-left:1.3rem;font-size:.88rem;line-height:1.6;color:#26262e;font-weight:400}
.spot-points li::before{content:"→";position:absolute;left:0;color:var(--danfo-deep);font-family:var(--mono)}
.spot-stack{display:flex;flex-wrap:wrap;gap:.5rem;margin-top:1.5rem}
.spot-stack span{font-family:var(--mono);font-size:.68rem;background:var(--ink);color:var(--paper);padding:.4rem .8rem;border-radius:100px}
.spot-link{display:inline-flex;align-items:center;gap:.6rem;margin-top:1.6rem;font-family:var(--body);font-weight:800;font-size:.95rem;color:var(--ink);border-bottom:2px solid var(--danfo);padding-bottom:.2rem;transition:color .3s}
.spot-link:hover{color:var(--danfo-deep)}
.spot-link svg{transition:transform .3s}
.spot-link:hover svg{transform:translateX(5px) rotate(-30deg)}
.spot-shot{display:block;border-radius:18px;overflow:hidden;border:1px solid #E4E0D4;box-shadow:0 24px 60px rgba(14,14,18,.18);transform:rotate(1.2deg);transition:transform .4s cubic-bezier(.22,1,.36,1),box-shadow .4s}
.spot-shot:hover{transform:rotate(0deg) scale(1.02);box-shadow:0 32px 80px rgba(14,14,18,.26)}
.spot-shot img{display:block;width:100%;height:auto}
@media(max-width:820px){.spot{grid-template-columns:1fr}.spot-shot{transform:none}.spot.flip>div:first-child{order:0}.spot.flip .spot-shot{order:0;transform:none}}

.contact{text-align:center;padding-bottom:clamp(3rem,8vh,5rem)}
.contact-big{font-family:var(--display);font-weight:900;font-size:clamp(2.6rem,9vw,7.5rem);line-height:1.02;letter-spacing:-.015em}
.contact-big .stroke{color:transparent;-webkit-text-stroke:1.5px var(--paper);font-style:italic;font-weight:600}
.contact-ctas{display:flex;justify-content:center;flex-wrap:wrap;gap:1rem;margin-top:clamp(2rem,5vh,3.2rem)}
.magnet{display:inline-flex;align-items:center;gap:.9rem;background:var(--danfo);color:var(--ink);font-family:var(--body);font-weight:800;font-size:clamp(.92rem,1.5vw,1.1rem);letter-spacing:.01em;padding:1.1rem 2.2rem;border-radius:100px;transition:background .3s,transform .15s ease-out}
.magnet:hover{background:var(--paper);color:var(--ink)}
.magnet svg{transition:transform .3s}
.magnet:hover svg{transform:translateX(5px) rotate(-30deg)}
.magnet.ghost{background:transparent;color:var(--paper);border:1.5px solid var(--line)}
.magnet.ghost:hover{border-color:var(--danfo);color:var(--danfo);background:transparent}
.magnet.ghost:hover svg{transform:translateY(3px) rotate(0)}
.contact-links{display:flex;justify-content:center;flex-wrap:wrap;gap:clamp(1.2rem,4vw,2.8rem);margin-top:clamp(2.4rem,6vh,4rem);font-family:var(--mono);font-size:.74rem;letter-spacing:.16em;text-transform:uppercase}
.contact-links a{position:relative;padding:.3rem 0;color:var(--smoke);transition:color .3s}
.contact-links a:hover{color:var(--danfo)}
footer{border-top:1px solid var(--line);padding:1.4rem clamp(1.2rem,4vw,3rem);display:flex;justify-content:space-between;flex-wrap:wrap;gap:.6rem;font-family:var(--mono);font-size:.64rem;letter-spacing:.14em;color:var(--smoke);text-transform:uppercase}

@media (prefers-reduced-motion:reduce){
  *,*::before,*::after{animation-duration:.01ms!important;animation-iteration-count:1!important;transition-duration:.01ms!important}
  html{scroll-behavior:auto}
  .site,.site button{cursor:auto}
  .cursor,.cursor-ring{display:none}
  .reveal{opacity:1;transform:none}
  .hero h1 .row>span{transform:none}
}
`;
